/**
 * PR / MR URL host parser.
 *
 * CC 2.1.119 extended `--from-pr` to accept GitLab MR, Bitbucket PR, and
 * GitHub Enterprise URLs in addition to github.com. This parser surfaces a
 * unified shape skills can branch on without re-implementing host detection.
 *
 * See: src/skills/chain-patterns/references/pr-from-platform.md
 */

export type PrHostFamily =
  | 'github'
  | 'github-enterprise'
  | 'gitlab'
  | 'gitlab-self'
  | 'bitbucket'
  | 'unknown';

export interface PrHostInfo {
  /** Hostname extracted from the URL, e.g. "github.com", "gitlab.acme.io" */
  readonly host: string;
  /** Host family for skill-side branching */
  readonly family: PrHostFamily;
  /** Owner / org / group segment of the URL */
  readonly owner: string;
  /** Repo / project segment */
  readonly repo: string;
  /** Numeric PR / MR id */
  readonly pr_id: number;
}

const PATTERNS: ReadonlyArray<{
  family: PrHostFamily;
  re: RegExp;
}> = [
  // github.com (public)
  {
    family: 'github',
    re: /^https?:\/\/(github\.com)\/([^/\s]+)\/([^/\s]+)\/pull\/(\d+)(?:[\/?#].*)?$/i,
  },
  // GitHub Enterprise — host containing ".github." (e.g. "github.acme.com",
  // "ghe.acme.com" — note: GHE typically uses internal hostnames; we match the
  // common `<corp>.github.<tld>` pattern. Self-hosted GHE on opaque hostnames
  // is best handled via prUrlTemplate (see configure skill).
  {
    family: 'github-enterprise',
    re: /^https?:\/\/([a-z0-9.-]+\.github\.[a-z]+)\/([^/\s]+)\/([^/\s]+)\/pull\/(\d+)(?:[\/?#].*)?$/i,
  },
  // GitLab.com (public)
  {
    family: 'gitlab',
    re: /^https?:\/\/(gitlab\.com)\/((?:[^/\s]+\/)*[^/\s]+?)\/([^/\s]+)\/-\/merge_requests\/(\d+)(?:[\/?#].*)?$/i,
  },
  // Self-hosted GitLab — host starts with "gitlab." or contains "/gitlab/"
  {
    family: 'gitlab-self',
    re: /^https?:\/\/(gitlab\.[a-z0-9.-]+)\/((?:[^/\s]+\/)*[^/\s]+?)\/([^/\s]+)\/-\/merge_requests\/(\d+)(?:[\/?#].*)?$/i,
  },
  // Bitbucket Cloud
  {
    family: 'bitbucket',
    re: /^https?:\/\/(bitbucket\.org)\/([^/\s]+)\/([^/\s]+)\/pull-requests\/(\d+)(?:[\/?#].*)?$/i,
  },
];

/**
 * Parse a PR / MR URL into a structured `PrHostInfo` shape.
 *
 * Returns `null` when no pattern matches — callers should treat this as
 * "fall back to github.com defaults" or surface an error to the user.
 */
export function parsePrUrl(url: string): PrHostInfo | null {
  if (typeof url !== 'string' || url.length === 0) return null;

  for (const { family, re } of PATTERNS) {
    const m = url.match(re);
    if (!m) continue;

    const [, host, ownerOrGroup, repo, idStr] = m;
    const pr_id = Number.parseInt(idStr, 10);
    if (!Number.isFinite(pr_id) || pr_id <= 0) return null;

    // GitLab supports nested groups (group/subgroup/repo). The owner field
    // collects the full path up to the repo segment.
    return {
      host,
      family,
      owner: ownerOrGroup,
      repo,
      pr_id,
    };
  }

  return null;
}

/**
 * Build a PR / MR URL from structured info using a `prUrlTemplate` (CC 2.1.119).
 *
 * Template tokens: `{host}`, `{owner}`, `{repo}`, `{n}`. Tokens not present
 * in the template are silently ignored (the template author owns shape).
 */
export function applyPrUrlTemplate(template: string, info: PrHostInfo): string {
  return template
    .replace(/\{host\}/g, info.host)
    .replace(/\{owner\}/g, info.owner)
    .replace(/\{repo\}/g, info.repo)
    .replace(/\{n\}/g, String(info.pr_id));
}
